import{_ as a,o as e,c as r,a4 as d}from"./chunks/framework.BybBnFXO.js";const p=JSON.parse('{"title":"碳酸盐","description":"","frontmatter":{"title":"碳酸盐","mineralGroup":"carbonates"},"headers":[],"relativePath":"zh/mineral-groups/carbonates.md","filePath":"zh/mineral-groups/carbonates.md","lastUpdated":1784177547000}'),o={name:"zh/mineral-groups/carbonates.md"};function i(n,t,l,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="碳酸盐" tabindex="-1">碳酸盐 <a class="header-anchor" href="#碳酸盐" aria-label="Permalink to &quot;碳酸盐&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>碳酸盐类涵盖宝石界多个富有特色的品种：</p><ul><li><strong>方解石族</strong>：方解石（含冰洲石）、菱锰矿、菱镁矿、菱铁矿、 蓝纹石（含 Sr 的蓝色方解石变种）</li><li><strong>文石族</strong>：文石（霰石）、珍珠母（生物成因）、珊瑚</li><li><strong>白云石、孔雀石、蓝铜矿</strong>：含水或铜的复杂碳酸盐 碳酸盐普遍硬度较低（Mohs 3–4），多为玉石或有机宝石原料。</li></ul><h2 id="化学式类型" tabindex="-1">化学式类型 <a class="header-anchor" href="#化学式类型" aria-label="Permalink to &quot;化学式类型&quot;">​</a></h2><p>CO₃²⁻ + 二价金属阳离子</p><h2 id="结构" tabindex="-1">结构 <a class="header-anchor" href="#结构" aria-label="Permalink to &quot;结构&quot;">​</a></h2><p>[CO₃]²⁻ 平面三角形基团与二价金属阳离子（Ca、Mg、Mn、Fe、Cu、 Zn、Ba、Sr）配位。方解石型为三方晶系；文石型为斜方晶系。</p><h2 id="代表性宝石" tabindex="-1">代表性宝石 <a class="header-anchor" href="#代表性宝石" aria-label="Permalink to &quot;代表性宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>化学式</th><th>亚族</th></tr></thead><tbody><tr><td>Calcite / 方解石</td><td>CaCO₃</td><td>calcite</td></tr><tr><td>Rhodochrosite / 菱锰矿</td><td>MnCO₃</td><td>calcite</td></tr><tr><td>Magnesite / 菱镁矿</td><td>MgCO₃</td><td>calcite</td></tr><tr><td>Aragonite / 文石</td><td>CaCO₃</td><td>aragonite</td></tr><tr><td>Malachite / 孔雀石</td><td>Cu₂CO₃(OH)₂</td><td>malachite</td></tr><tr><td>Azurite / 蓝铜矿</td><td>Cu₃(CO₃)₂(OH)₂</td><td>azurite</td></tr><tr><td>Smithsonite / 菱锌矿</td><td>ZnCO₃</td><td>calcite</td></tr></tbody></table><p><em>详见<a href="./intro.html">矿物组总览</a>。</em></p>',11)])])}